    int maxPalindromes(string s, int k) {
        int count = 0;
        for (int i = 0; i < s.size() - k + 1; i++) {
            string sub = s.substr(i, k);
            if (isPalindrome(sub)) {
                count++;
            }
        }
        return count;
    }
    bool isPalindrome(string s) {
